/// Static-only profiles (include_notify=false) must NOT have listener fields.
#[test]
fn seccomp_static_only_has_no_listener() {
    let profile = puzzled::seccomp_profile::generate_seccomp_profile(
        "branch-static",
        Path::new("/run/puzzled/seccomp.sock"),
        false,
        false,
        SeccompMode::Permissive,
    )
    .unwrap();

    assert!(profile.listener_path.is_none());
    assert!(profile.listener_metadata.is_none());
    assert!(
        !profile
            .syscalls
            .iter()
            .any(|r| r.action == "SCMP_ACT_NOTIFY"),
        "static-only profile must not have NOTIFY rules"
    );
}

