// 3. OCI hook annotation contract
// ═══════════════════════════════════════════════════════════════════════════

/// Annotation keys/values must match the contract between puzzle-podman
/// (producer) and puzzle-hook (consumer).
#[test]
fn oci_hook_recognizes_puzzle_podman_annotations() {
    let state_json = make_oci_state_json(
        "creating",
        Some(12345),
        &[
            ("run.oci.handler", "puzzlepod"),
            ("org.lobstertrap.puzzlepod.branch", "branch-abc-123"),
        ],
    );

    let state: serde_json::Value = serde_json::from_str(&state_json).unwrap();
    let annotations = state["annotations"].as_object().unwrap();

    assert_eq!(
        annotations.get("run.oci.handler").and_then(|v| v.as_str()),
        Some("puzzlepod"),
    );
    assert_eq!(
        annotations
            .get("org.lobstertrap.puzzlepod.branch")
            .and_then(|v| v.as_str()),
        Some("branch-abc-123"),
    );
}

/// Containers without the handler annotation must not trigger the hook.
#[test]
fn oci_hook_skips_non_puzzlepod_containers() {
    let state_json = make_oci_state_json(
        "creating",
        Some(12345),
        &[("some.other.annotation", "value")],
    );

    let state: serde_json::Value = serde_json::from_str(&state_json).unwrap();
    assert!(state["annotations"]
        .as_object()
        .unwrap()
        .get("run.oci.handler")
        .is_none());
}

/// Poststop stage may not have a PID (process already exited).
#[test]
fn oci_state_poststop_no_pid() {
    let state_json = make_oci_state_json(
        "stopped",
        None,
        &[
            ("run.oci.handler", "puzzlepod"),
            ("org.lobstertrap.puzzlepod.branch", "branch-xyz"),
        ],
    );

    let state: serde_json::Value = serde_json::from_str(&state_json).unwrap();
    assert!(state["pid"].is_null());
}

/// OCI state status field must match the expected hook stage values.
#[test]
fn oci_state_status_values_valid() {
    for status in &["creating", "stopped"] {
        let state_json = make_oci_state_json(
            status,
            Some(1234),
            &[
                ("run.oci.handler", "puzzlepod"),
                ("org.lobstertrap.puzzlepod.branch", "branch-1"),
            ],
        );
        let state: serde_json::Value = serde_json::from_str(&state_json).unwrap();
        assert_eq!(state["status"].as_str(), Some(*status));
    }
}

