/// Generate seccomp profile, write to disk, read back, verify all fields.
#[test]
fn seccomp_profile_write_read_roundtrip() {
    let dir = tempfile::tempdir().unwrap();
    let output_path = dir.path().join("seccomp.json");

    let profile = puzzled::seccomp_profile::generate_seccomp_profile(
        "roundtrip-branch",
        Path::new("/run/puzzled/seccomp.sock"),
        true,
        true,
        SeccompMode::Permissive,
    )
    .unwrap();

    puzzled::seccomp_profile::write_seccomp_profile(&profile, &output_path).unwrap();

    let contents = std::fs::read_to_string(&output_path).unwrap();
    let deserialized: puzzled::seccomp_profile::OciSeccompProfile =
        serde_json::from_str(&contents).unwrap();

    assert_eq!(deserialized.default_action, profile.default_action);
    assert_eq!(deserialized.default_errno_ret, profile.default_errno_ret);
    assert_eq!(deserialized.listener_path, profile.listener_path);
    assert_eq!(deserialized.listener_metadata, profile.listener_metadata);
    assert_eq!(deserialized.architectures, profile.architectures);
    assert_eq!(deserialized.syscalls.len(), profile.syscalls.len());
}

/// Generate landlock rules, write to disk, read back, verify.
#[test]
fn landlock_rules_write_read_roundtrip() {
    let dir = tempfile::tempdir().unwrap();
    let output_path = dir.path().join("landlock.json");

    let profile = create_test_profile("standard");
    let rules = puzzled::landlock_rules::generate_landlock_rules(&profile, Path::new("/workspace"))
        .unwrap();

    puzzled::landlock_rules::write_landlock_rules(&rules, &output_path).unwrap();

    let contents = std::fs::read_to_string(&output_path).unwrap();
    let parsed: serde_json::Value = serde_json::from_str(&contents).unwrap();

    assert_eq!(parsed["abi"].as_str(), Some("V5"));
    let write_paths: Vec<&str> = parsed["write"]
        .as_array()
        .unwrap()
        .iter()
        .filter_map(|v| v.as_str())
        .collect();
    assert!(write_paths.contains(&"/workspace"));
    assert_eq!(parsed["read"].as_array().unwrap().len(), rules.read.len());
    assert_eq!(parsed["exec"].as_array().unwrap().len(), rules.exec.len());
}

