// ═══════════════════════════════════════════════════════════════════════════

/// Critical escape-vector syscalls must be in the KILL_PROCESS tier.
#[test]
fn seccomp_denies_critical_escape_vectors() {
    let profile = puzzled::seccomp_profile::generate_seccomp_profile(
        "test-branch",
        Path::new("/run/puzzled/seccomp.sock"),
        true,
        false,
        SeccompMode::Permissive,
    )
    .unwrap();

    let deny_rule = profile
        .syscalls
        .iter()
        .find(|r| r.action == "SCMP_ACT_KILL_PROCESS")
        .expect("must have KILL_PROCESS rule");

    let critical = [
        "ptrace",
        "mount",
        "umount2",
        "setns",
        "unshare",
        "bpf",
        "kexec_load",
        "init_module",
        "finit_module",
        "pivot_root",
        "chroot",
        "io_uring_setup",
        "process_vm_readv",
        "process_vm_writev",
    ];

    for syscall in &critical {
        assert!(
            deny_rule.names.contains(&syscall.to_string()),
            "{syscall} must be in KILL_PROCESS deny list"
        );
    }
}

/// Socket type filtering must block raw sockets.
#[test]
fn seccomp_blocks_raw_sockets() {
    let profile = puzzled::seccomp_profile::generate_seccomp_profile(
        "test-branch",
        Path::new("/run/puzzled/seccomp.sock"),
        true,
        false,
        SeccompMode::Permissive,
    )
    .unwrap();

    let socket_rules: Vec<_> = profile
        .syscalls
        .iter()
        .filter(|r| r.action == "SCMP_ACT_ERRNO" && r.names.contains(&"socket".to_string()))
        .collect();

    assert!(socket_rules.len() >= 2, "must block SOCK_RAW + SOCK_PACKET");

    let blocked_values: Vec<u64> = socket_rules
        .iter()
        .filter_map(|r| r.args.as_ref())
        .flat_map(|args| args.iter().map(|a| a.value))
        .collect();

    assert!(blocked_values.contains(&3), "SOCK_RAW (3) must be blocked");
    assert!(
        blocked_values.contains(&10),
        "SOCK_PACKET (10) must be blocked"
    );
}

/// Clone guard adds clone/clone3 to NOTIFY tier.
#[test]
fn seccomp_clone_guard_when_enabled() {
    let profile = puzzled::seccomp_profile::generate_seccomp_profile(
        "test-branch",
        Path::new("/run/puzzled/seccomp.sock"),
        true,
        true,
        SeccompMode::Permissive,
    )
    .unwrap();

    let notify = profile
        .syscalls
        .iter()
        .find(|r| r.action == "SCMP_ACT_NOTIFY")
        .unwrap();

    assert!(notify.names.contains(&"clone".to_string()));
    assert!(notify.names.contains(&"clone3".to_string()));
}

#[test]
fn seccomp_no_clone_guard_when_disabled() {
    let profile = puzzled::seccomp_profile::generate_seccomp_profile(
        "test-branch",
        Path::new("/run/puzzled/seccomp.sock"),
        true,
        false,
        SeccompMode::Permissive,
    )
    .unwrap();

    let notify = profile
        .syscalls
        .iter()
        .find(|r| r.action == "SCMP_ACT_NOTIFY")
        .unwrap();

    assert!(!notify.names.contains(&"clone".to_string()));
    assert!(!notify.names.contains(&"clone3".to_string()));
}

