/// Privileged profile generates broader rules than restricted.
#[test]
fn landlock_rules_privileged_broader_than_restricted() {
    let restricted = create_restricted_profile();
    let privileged = create_privileged_profile();

    let r_rules =
        puzzled::landlock_rules::generate_landlock_rules(&restricted, Path::new("/workspace"))
            .unwrap();
    let p_rules =
        puzzled::landlock_rules::generate_landlock_rules(&privileged, Path::new("/workspace"))
            .unwrap();

    assert!(p_rules.read.len() >= r_rules.read.len());
    assert!(p_rules.write.len() >= r_rules.write.len());
}

/// exec_allowlist maps to the exec field in generated rules.
#[test]
fn landlock_rules_exec_matches_profile() {
    let mut profile = create_test_profile("standard");
    profile.exec_allowlist = vec![
        "/usr/bin/python3".to_string(),
        "/usr/bin/git".to_string(),
        "/usr/bin/cargo".to_string(),
    ];

    let rules = puzzled::landlock_rules::generate_landlock_rules(&profile, Path::new("/workspace"))
        .unwrap();

    assert_eq!(rules.exec.len(), 3);
    assert!(rules.exec.contains(&"/usr/bin/python3".to_string()));
    assert!(rules.exec.contains(&"/usr/bin/git".to_string()));
    assert!(rules.exec.contains(&"/usr/bin/cargo".to_string()));
}

/// allow_symlinks in profile maps to allow_refer in Landlock rules.
#[test]
fn landlock_rules_allow_refer_from_profile() {
    let mut profile = create_test_profile("standard");
    profile.allow_symlinks = true;
    let rules = puzzled::landlock_rules::generate_landlock_rules(&profile, Path::new("/workspace"))
        .unwrap();
    assert!(
        rules.allow_refer,
        "allow_refer must be true when allow_symlinks=true"
    );

    profile.allow_symlinks = false;
    let rules = puzzled::landlock_rules::generate_landlock_rules(&profile, Path::new("/workspace"))
        .unwrap();
    assert!(
        !rules.allow_refer,
        "allow_refer must be false when allow_symlinks=false"
    );
}

// ═══════════════════════════════════════════════════════════════════════════
// 8. Full Podman-native artifact generation flow
// ═══════════════════════════════════════════════════════════════════════════

/// Simulate the complete artifact generation flow:
/// 1. Generate seccomp profile
/// 2. Generate landlock rules
/// 3. Write both to disk
/// 4. Verify both are parseable and cross-compatible
#[test]
fn full_podman_native_artifact_generation() {
    let dir = tempfile::tempdir().unwrap();
    let branch_id = "flow-test-branch-42";
    let branch_dir = dir.path().join(branch_id);
    std::fs::create_dir_all(&branch_dir).unwrap();

    let profile = create_test_profile("standard");

    // Generate seccomp profile
    let seccomp = puzzled::seccomp_profile::generate_seccomp_profile(
        branch_id,
        Path::new("/run/puzzled/seccomp-notify.sock"),
        true,
        false,
        SeccompMode::Permissive,
    )
    .unwrap();
    let seccomp_path = branch_dir.join("seccomp.json");
    puzzled::seccomp_profile::write_seccomp_profile(&seccomp, &seccomp_path).unwrap();

    // Generate landlock rules
    let workspace = branch_dir.join("merged");
    std::fs::create_dir_all(&workspace).unwrap();
    let landlock = puzzled::landlock_rules::generate_landlock_rules(&profile, &workspace).unwrap();
    let landlock_path = branch_dir.join("landlock.json");
    puzzled::landlock_rules::write_landlock_rules(&landlock, &landlock_path).unwrap();

    // Verify both files exist and are valid JSON
    assert!(seccomp_path.exists());
    assert!(landlock_path.exists());

    let seccomp_json: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&seccomp_path).unwrap()).unwrap();
    let landlock_json: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&landlock_path).unwrap()).unwrap();

    // Seccomp must allow Landlock syscalls
    let allows: Vec<&str> = seccomp_json["syscalls"]
        .as_array()
        .unwrap()
        .iter()
        .filter(|r| r["action"].as_str() == Some("SCMP_ACT_ALLOW"))
        .flat_map(|r| {
            r["names"]
                .as_array()
                .unwrap()
                .iter()
                .filter_map(|n| n.as_str())
        })
        .collect();
    assert!(allows.contains(&"landlock_create_ruleset"));

    // Seccomp must NOTIFY on execve
    let notifies: Vec<&str> = seccomp_json["syscalls"]
        .as_array()
        .unwrap()
        .iter()
        .filter(|r| r["action"].as_str() == Some("SCMP_ACT_NOTIFY"))
        .flat_map(|r| {
            r["names"]
                .as_array()
                .unwrap()
                .iter()
                .filter_map(|n| n.as_str())
        })
        .collect();
    assert!(notifies.contains(&"execve"));

    // Landlock workspace must be writable
    let writes: Vec<&str> = landlock_json["write"]
        .as_array()
        .unwrap()
        .iter()
        .filter_map(|v| v.as_str())
        .collect();
    assert!(writes.iter().any(|p| p.contains("merged")));

    // listenerMetadata branch_id must match
    let metadata: serde_json::Value =
        serde_json::from_str(seccomp_json["listenerMetadata"].as_str().unwrap()).unwrap();
    assert_eq!(metadata["branch_id"].as_str(), Some(branch_id));
}

// ═══════════════════════════════════════════════════════════════════════════
// 9. J81: read_denylist / write_denylist filtering
// ═══════════════════════════════════════════════════════════════════════════

/// J81: Paths in read_denylist must be excluded from generated Landlock read rules.
#[test]
fn j81_landlock_rules_excludes_read_denylist() {
    let mut profile = create_test_profile("denylist-test");
    profile.filesystem.read_allowlist = vec![
        PathBuf::from("/usr"),
        PathBuf::from("/proc/kcore"),
        PathBuf::from("/sys/firmware"),
    ];
    // J81: read_denylist should filter read paths independently of the general denylist
    profile.filesystem.read_denylist =
        vec![PathBuf::from("/proc/kcore"), PathBuf::from("/sys/firmware")];
    // General denylist is empty — only read_denylist should apply
    profile.filesystem.denylist = vec![];

    let rules = puzzled::landlock_rules::generate_landlock_rules(&profile, Path::new("/workspace"))
        .unwrap();

    assert!(
        rules.read.contains(&"/usr".to_string()),
        "J81: /usr should be in read rules (not in read_denylist)"
    );
    assert!(
        !rules.read.contains(&"/proc/kcore".to_string()),
        "J81: /proc/kcore must be excluded by read_denylist"
    );
    assert!(
        !rules.read.contains(&"/sys/firmware".to_string()),
        "J81: /sys/firmware must be excluded by read_denylist"
    );
}

/// J81: Paths in write_denylist must be excluded from generated Landlock write rules.
#[test]
fn j81_landlock_rules_excludes_write_denylist() {
    let mut profile = create_test_profile("write-denylist-test");
    profile.filesystem.write_allowlist = vec![PathBuf::from("/tmp"), PathBuf::from("/boot")];
    profile.filesystem.write_denylist = vec![PathBuf::from("/boot")];
    profile.filesystem.denylist = vec![];

    let rules = puzzled::landlock_rules::generate_landlock_rules(&profile, Path::new("/workspace"))
        .unwrap();

    assert!(
        rules.write.contains(&"/tmp".to_string()),
        "J81: /tmp should be in write rules (not in write_denylist)"
    );
    assert!(
        !rules.write.contains(&"/boot".to_string()),
        "J81: /boot must be excluded by write_denylist"
    );
    // Workspace is always included regardless of denylists
    assert!(
        rules.write.contains(&"/workspace".to_string()),
        "J81: workspace must always be writable"
    );
}

