fn make_oci_state_json(status: &str, pid: Option<u32>, annotations: &[(&str, &str)]) -> String {
    let pid_field = match pid {
        Some(p) => format!("{p}"),
        None => "null".to_string(),
    };
    let ann_entries: Vec<String> = annotations
        .iter()
        .map(|(k, v)| format!(r#""{k}": "{v}""#))
        .collect();

    format!(
        r#"{{
  "ociVersion": "1.0.2",
  "id": "test-container-001",
  "status": "{status}",
  "pid": {pid_field},
  "bundle": "/run/containers/storage/overlay-containers/abc/userdata",
  "annotations": {{ {ann} }}
}}"#,
        ann = ann_entries.join(", ")
    )
}

// ═══════════════════════════════════════════════════════════════════════════
// L60: puzzle-podman symlink resolution for MERGED_DIR/SECCOMP_PATH/LANDLOCK_PATH
// ═══════════════════════════════════════════════════════════════════════════

/// L60: puzzle-podman must resolve symlinks with `readlink -f` for MERGED_DIR,
/// SECCOMP_PATH, and LANDLOCK_PATH to prevent symlink-based path traversal.
/// A symlink like /var/lib/puzzled/branches/evil/merged -> /etc/ would pass
/// the textual prefix check but point outside the allowed directory.
#[test]
fn l60_puzzle_podman_resolves_symlinks_for_paths() {
    let source = include_str!("../../../podman/puzzle-podman");

    // MERGED_DIR must have readlink -f resolution
    assert!(
        source.contains("MERGED_DIR_REAL=\"$(readlink -f"),
        "L60: puzzle-podman must resolve MERGED_DIR symlinks with readlink -f"
    );

    // SECCOMP_PATH must have readlink -f resolution
    assert!(
        source.contains("SECCOMP_PATH_REAL=\"$(readlink -f"),
        "L60: puzzle-podman must resolve SECCOMP_PATH symlinks with readlink -f"
    );

    // LANDLOCK_PATH must have readlink -f resolution
    assert!(
        source.contains("LANDLOCK_PATH_REAL=\"$(readlink -f"),
        "L60: puzzle-podman must resolve LANDLOCK_PATH symlinks with readlink -f"
    );
}
